const now = new Date();
const month = now.getMonth() + 1;

let season, services;

if (month >= 3 && month <= 5) {
  season = 'Spring';
  services = 'spring cleanup, aeration, fertilization, weed control, dethatching';
} else if (month >= 6 && month <= 8) {
  season = 'Summer';
  services = 'weekly mowing, garden bed maintenance, bush trimming, pest control, irrigation';
} else if (month >= 9 && month <= 11) {
  season = 'Fall';
  services = 'fall cleanup, leaf removal, overseeding, aeration, gutter cleaning';
} else {
  season = 'Winter';
  services = 'snow removal, gutter guard installation, holiday lighting, winter prep';
}

const year = now.getFullYear();
const quarterNum = Math.ceil(month / 3);
const quarter = `${year}-Q${quarterNum}`;

return [{ json: { season, services, quarter, year } }];

