const response = $input.first().json;
const content = response.content[0].text;

let faqs;
try {
  faqs = JSON.parse(content);
} catch (e) {
  // Try to extract JSON array from response
  const match = content.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (match) {
    faqs = JSON.parse(match[0]);
  } else {
    throw new Error('Could not parse FAQ response: ' + content.substring(0, 200));
  }
}

const season = $('Determine Current Season').first().json.season;
const quarter = $('Determine Current Season').first().json.quarter;

// Format for Telegram
let telegramText = `\u2728 SEASONAL FAQ ROTATION - ${season} ${new Date().getFullYear()}\n\n`;
faqs.forEach((faq, i) => {
  telegramText += `\u2753 Q${i + 1}: ${faq.q}\n`;
  telegramText += `\u2705 A: ${faq.a}\n\n`;
});
telegramText += `These FAQs are ready to update on your GBP profile.\n`;
telegramText += `Go to: business.google.com > Info > Q&A\n\n`;
telegramText += `Reply 'faq-approved' to mark as done.`;

return [{ json: { faqs, season, quarter, telegramText, faqCount: faqs.length } }];
